// Package hex is a drop-in fast path for hexadecimal (base16) encoding and
// decoding, byte- AND error-identical to the standard library's encoding/hex.
// Both directions run a SIMD kernel generated by go-asmgen (amd64 SSE2/SSSE3,
// with an AVX2 path; other architectures fall back to the standard library):
// encoding vectorises the nibble->ASCII mapping; decoding vectorises the
// ASCII->nibble mapping with parallel validity detection. The short tail (and,
// for decode, any block containing an invalid char) reuses an
// encoding/hex-equivalent scalar loop so the output and the exact
// InvalidByteError / ErrLength errors land at the same offsets.
package hex

import "encoding/hex"

// reverseHexTable maps a hex char to its 0..15 nibble value, or a value > 0x0f
// for any non-hex byte. It is identical to encoding/hex's table, so the scalar
// decode tail below reproduces stdlib error offsets exactly.
var reverseHexTable = [256]byte{
	0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff,
	0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff,
	0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff,
	0x00, 0x01, 0x02, 0x03, 0x04, 0x05, 0x06, 0x07, 0x08, 0x09, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff,
	0xff, 0x0a, 0x0b, 0x0c, 0x0d, 0x0e, 0x0f, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff,
	0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff,
	0xff, 0x0a, 0x0b, 0x0c, 0x0d, 0x0e, 0x0f, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff,
	0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff,
	0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff,
	0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff,
	0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff,
	0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff,
	0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff,
	0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff,
	0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff,
	0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff,
}

// EncodedLen returns the length of an encoding of n source bytes: exactly 2n.
func EncodedLen(n int) int { return hex.EncodedLen(n) }

// Encode encodes src into EncodedLen(len(src)) bytes of dst, writing lowercase
// hexadecimal. It returns the number of bytes written, len(src)*2. Output is
// identical to encoding/hex.Encode.
func Encode(dst, src []byte) int {
	sd, dd := encodeSIMD(dst, src)
	hex.Encode(dst[dd:], src[sd:])
	return EncodedLen(len(src))
}

// EncodeToString returns the lowercase hexadecimal encoding of src, identical to
// encoding/hex.EncodeToString.
func EncodeToString(src []byte) string {
	dst := make([]byte, EncodedLen(len(src)))
	Encode(dst, src)
	return string(dst)
}

// DecodedLen returns the length of a decoding of n hexadecimal bytes: n/2.
func DecodedLen(n int) int { return hex.DecodedLen(n) }

// Decode decodes src into DecodedLen(len(src)) bytes, returning the number of
// bytes written. It is byte- AND error-identical to encoding/hex.Decode: a SIMD
// kernel decodes whole valid blocks; a scalar tail (identical to stdlib's loop)
// finishes the remainder and, on the first invalid char or odd length, returns
// the exact InvalidByteError offset or ErrLength.
func Decode(dst, src []byte) (int, error) {
	dd, sd := decodeSIMD(dst, src)
	return decodeScalar(dst, src, dd, sd)
}

// DecodeString returns the bytes represented by the hexadecimal string s,
// identical to encoding/hex.DecodeString.
func DecodeString(s string) ([]byte, error) {
	src := []byte(s)
	dst := make([]byte, DecodedLen(len(src)))
	n, err := Decode(dst, src)
	return dst[:n], err
}

// decodeScalar resumes decoding from src[sd:] into dst[dd:], reproducing
// encoding/hex.Decode's loop, errors and offsets exactly. dd bytes have already
// been written and sd source bytes consumed by the SIMD kernel (always an even
// sd, so j stays paired). It returns the total bytes written and any error.
func decodeScalar(dst, src []byte, dd, sd int) (int, error) {
	i, j := dd, sd+1
	for ; j < len(src); j += 2 {
		p := src[j-1]
		q := src[j]
		a := reverseHexTable[p]
		b := reverseHexTable[q]
		if a > 0x0f {
			return i, hex.InvalidByteError(p)
		}
		if b > 0x0f {
			return i, hex.InvalidByteError(q)
		}
		dst[i] = (a << 4) | b
		i++
	}
	if len(src)%2 == 1 {
		// An invalid char (if present) is an earlier problem than bad length.
		if reverseHexTable[src[j-1]] > 0x0f {
			return i, hex.InvalidByteError(src[j-1])
		}
		return i, hex.ErrLength
	}
	return i, nil
}
